import torchimport torch.nn as nnimport torch.nn.functional as Ffrom wenet.transformer.encoder_cat import ConformerEncoderfrom speechbrain.lobes.models.ECAPA_TDNN import AttentiveStatisticsPooling, BatchNorm1dfrom wenet.utils.mask import make_pad_maskclass EnhancedConv1d(nn.Module):    """增强的1D卷积模块，替换深度可分离卷积"""        def __init__(self, in_channels, out_channels, kernel_size, padding=0, dilation=1, groups=1):        super(EnhancedConv1d, self).__init__()        self.conv = nn.Conv1d(            in_channels, out_channels, kernel_size,            padding=padding, dilation=dilation, groups=groups        )        self.bn = nn.BatchNorm1d(out_channels)        self.activation = nn.SiLU(inplace=True)  # 使用SiLU激活函数，比ReLU更好            def forward(self, x):        x = self.conv(x)        x = self.bn(x)        x = self.activation(x)        return xclass MultiScaleSemanticFusion(nn.Module):    """    多尺度语义融合模块    在相同时间分辨率下，融合不同语义层次的特征    """    def __init__(self, channels, num_scales=3, reduction=16):        super(MultiScaleSemanticFusion, self).__init__()        self.channels = channels        self.num_scales = num_scales        # 多尺度语义提取卷积 - 使用增强卷积        self.semantic_convs = nn.ModuleList([            nn.Sequential(                EnhancedConv1d(channels, channels, kernel_size=3 + i * 4, padding=1 + i * 2),                EnhancedConv1d(channels, channels, kernel_size=1)  # 额外的1x1卷积增强表达能力            ) for i in range(num_scales)        ])        # 语义注意力机制        self.semantic_attention = nn.Sequential(            nn.AdaptiveAvgPool1d(1),            nn.Flatten(),            nn.Linear(channels * num_scales, channels * num_scales // reduction),            nn.SiLU(inplace=True),            nn.Linear(channels * num_scales // reduction, num_scales),            nn.Softmax(dim=1)        )        # 分别归一化的权重参数        self.additive_weights = nn.Parameter(torch.ones(3))  # α, β, γ - 加性融合权重        self.multiplicative_weights = nn.Parameter(torch.ones(2))  # δ, ε - 乘性融合权重    def forward(self, low_feat, mid_feat, high_feat):        """        Args:            low_feat: [B, C, T] 低层语义特征 - 细节丰富            mid_feat: [B, C, T] 中层语义特征 - 平衡语义            high_feat: [B, C, T] 高层语义特征 - 强语义        Returns:            fused_feat: [B, C, T] 融合后的特征        """        batch_size, channels, time_steps = low_feat.shape        # 1. 多尺度语义特征提取        semantic_features = []        # 对每个输入特征应用多尺度卷积        for feat in [low_feat, mid_feat, high_feat]:            scale_features = []            for conv in self.semantic_convs:                scale_feat = conv(feat)  # [B, C, T]                scale_features.append(scale_feat)            # 拼接多尺度特征 [B, C*num_scales, T]            multi_scale_feat = torch.cat(scale_features, dim=1)            semantic_features.append(multi_scale_feat)        # 2. 语义注意力加权融合        # 计算每个语义层次的注意力权重        attention_weights = []        for feat in semantic_features:            # [B, C*num_scales, T] -> [B, num_scales]            attn = self.semantic_attention(feat)            attention_weights.append(attn)        # 3. 加权融合多尺度特征        weighted_features = []        for feat, weights in zip(semantic_features, attention_weights):            # 将特征拆分为多尺度 [B, C*num_scales, T] -> num_scales * [B, C, T]            scale_feats = torch.chunk(feat, self.num_scales, dim=1)            # 应用注意力权重            weighted_feat = sum(w.unsqueeze(-1).unsqueeze(-1) * scale_f                                for w, scale_f in zip(weights.unbind(1), scale_feats))            weighted_features.append(weighted_feat)        low_semantic, mid_semantic, high_semantic = weighted_features        # 4. 分别归一化的语义层次融合        # 加性融合权重归一化        additive_weights = F.softmax(self.additive_weights, dim=0)        α, β, γ = additive_weights        # 乘性融合权重归一化        multiplicative_weights = F.softmax(self.multiplicative_weights, dim=0)        δ, ε = multiplicative_weights        # 加性融合：线性组合不同语义层次        additive_fusion = (α * low_semantic +                           β * mid_semantic +                           γ * high_semantic)        # 乘性融合：语义指导的特征调制        multiplicative_fusion = (δ * low_semantic * mid_semantic +                                 ε * low_semantic * high_semantic)        # 总融合        fused_feat = additive_fusion + multiplicative_fusion        return fused_feat    def get_fusion_equation(self):        """返回融合公式"""        additive_weights = F.softmax(self.additive_weights, dim=0)        multiplicative_weights = F.softmax(self.multiplicative_weights, dim=0)        α, β, γ = additive_weights.detach().cpu().numpy()        δ, ε = multiplicative_weights.detach().cpu().numpy()        equation = f"F_out = {α:.3f}·Low + {β:.3f}·Mid + {γ:.3f}·High + "        equation += f"{δ:.3f}·(Low⊙Mid) + {ε:.3f}·(Low⊙High)"        return equationclass SemanticAwareAttention(nn.Module):    """语义感知注意力机制"""    def __init__(self, channels, num_heads=8):        super(SemanticAwareAttention, self).__init__()        self.num_heads = num_heads        self.head_dim = channels // num_heads        self.query = nn.Linear(channels, channels)        self.key = nn.Linear(channels, channels)        self.value = nn.Linear(channels, channels)        # 语义门控机制        self.semantic_gate = nn.Sequential(            nn.Linear(channels * 3, channels),            nn.Sigmoid()        )        self.out_proj = nn.Linear(channels, channels)    def forward(self, low_feat, mid_feat, high_feat):        """        基于语义相似性的注意力融合        """        batch_size, channels, time_steps = low_feat.shape        # 转换维度 [B, C, T] -> [B, T, C]        low_feat = low_feat.permute(0, 2, 1)        mid_feat = mid_feat.permute(0, 2, 1)        high_feat = high_feat.permute(0, 2, 1)        # 使用高层特征作为query，低层特征作为key和value（语义指导）        Q = self.query(high_feat)  # [B, T, C]        K = self.key(low_feat)  # [B, T, C]        V = self.value(low_feat)  # [B, T, C]        # 多头注意力        Q = Q.view(batch_size, -1, self.num_heads, self.head_dim).transpose(1, 2)        K = K.view(batch_size, -1, self.num_heads, self.head_dim).transpose(1, 2)        V = V.view(batch_size, -1, self.num_heads, self.head_dim).transpose(1, 2)        # 注意力计算        scores = torch.matmul(Q, K.transpose(-2, -1)) / (self.head_dim ** 0.5)        attn_weights = F.softmax(scores, dim=-1)        # 应用注意力        attn_output = torch.matmul(attn_weights, V)        attn_output = attn_output.transpose(1, 2).contiguous().view(            batch_size, -1, channels)        # 语义门控融合        semantic_context = torch.cat([low_feat, mid_feat, high_feat], dim=-1)        gate_weights = self.semantic_gate(semantic_context)        # 门控输出        output = gate_weights * attn_output + (1 - gate_weights) * low_feat        output = self.out_proj(output)        # 转换回 [B, C, T]        output = output.permute(0, 2, 1)        return outputclass EnhancedSemanticFeaturePyramidNoRefinement(nn.Module):    """    去除语义精炼层的增强语义特征金字塔网络 (ES-FPN without refinement)    在相同时间分辨率下实现多语义层次融合    """    def __init__(self, in_channels, out_channels=256, use_attention=True):        super(EnhancedSemanticFeaturePyramidNoRefinement, self).__init__()        self.out_channels = out_channels        self.use_attention = use_attention        # 语义特征投影层 - 使用增强卷积        self.semantic_projection = nn.ModuleList([            nn.Sequential(                EnhancedConv1d(in_channels, out_channels, 3, padding=1),                EnhancedConv1d(out_channels, out_channels, 1)  # 额外的1x1卷积增强表达能力            ) for _ in range(3)  # 低、中、高三个语义层次        ])        # 多尺度语义融合        self.semantic_fusion = MultiScaleSemanticFusion(out_channels)        # 语义感知注意力        if use_attention:            self.semantic_attention = SemanticAwareAttention(out_channels)        # 去除语义精炼层        # self.refinement_conv 被移除        # 残差连接 - 使用增强卷积        self.residual_conv = nn.Sequential(            EnhancedConv1d(in_channels, out_channels, 1),            EnhancedConv1d(out_channels, out_channels, 1)        )        # 分别归一化的输出权重        self.semantic_weights = nn.Parameter(torch.ones(1))  # 语义融合权重        self.attention_weights = nn.Parameter(torch.ones(1))  # 注意力融合权重    def forward(self, feat_low, feat_mid, feat_high):        """        前向传播 - 相同时间分辨率下的语义融合        Args:            feat_low: [B, C, T] 低层语义特征（块0-1）            feat_mid: [B, C, T] 中层语义特征（块2-3）            feat_high: [B, C, T] 高层语义特征（块4-5）        Returns:            fused_feat: [B, C, T] 融合后的语义特征        """        # 1. 语义特征投影        proj_low = self.semantic_projection[0](feat_low)        proj_mid = self.semantic_projection[1](feat_mid)        proj_high = self.semantic_projection[2](feat_high)        # 2. 多尺度语义融合        semantic_fused = self.semantic_fusion(proj_low, proj_mid, proj_high)        # 3. 语义感知注意力（可选）        if self.use_attention:            attention_fused = self.semantic_attention(proj_low, proj_mid, proj_high)            # 分别归一化的自适应融合            fusion_weights = F.softmax(torch.stack([self.semantic_weights, self.attention_weights]), dim=0)            w_semantic, w_attention = fusion_weights            fused_feat = w_semantic * semantic_fused + w_attention * attention_fused        else:            fused_feat = semantic_fused        # 4. 语义特征精炼 - 已移除        # refined_feat = self.refinement_conv(fused_feat)  # 注释掉这一行        # 5. 残差连接        if feat_low.size(1) == self.out_channels:            residual = feat_low        else:            residual = self.residual_conv(feat_low)        # 直接使用融合后的特征，不经过精炼        output = fused_feat + residual        return output    def get_fusion_info(self):        """返回融合信息"""        semantic_eq = self.semantic_fusion.get_fusion_equation()        if self.use_attention:            fusion_weights = F.softmax(torch.stack([self.semantic_weights, self.attention_weights]), dim=0)            w_semantic, w_attention = fusion_weights.detach().cpu().numpy()            attention_info = f" + 融合权重: 语义[{w_semantic:.3f}] 注意力[{w_attention:.3f}]"        else:            attention_info = ""        return f"语义融合(无精炼): {semantic_eq}{attention_info}"class CrossAttentionFusion(nn.Module):    """交叉注意力融合模块"""    def __init__(self, channels, num_heads=4, dropout=0.1):        super(CrossAttentionFusion, self).__init__()        self.num_heads = num_heads        self.head_dim = channels // num_heads        self.query_proj = nn.Linear(channels, channels)        self.key_proj = nn.Linear(channels, channels)        self.value_proj = nn.Linear(channels, channels)        self.out_proj = nn.Linear(channels, channels)        self.dropout = nn.Dropout(dropout)        self.norm1 = nn.LayerNorm(channels)        self.norm2 = nn.LayerNorm(channels)        self.ffn = nn.Sequential(            nn.Linear(channels, channels * 4),            nn.SiLU(),  # 使用SiLU激活函数            nn.Dropout(dropout),            nn.Linear(channels * 4, channels)        )    def forward(self, feat1, feat2):        batch_size, channels, time_steps = feat1.size()        feat1 = feat1.permute(0, 2, 1)        feat2 = feat2.permute(0, 2, 1)        residual = feat1        feat1 = self.norm1(feat1)        feat2 = self.norm1(feat2)        Q = self.query_proj(feat1)        K = self.key_proj(feat2)        V = self.value_proj(feat2)        Q = Q.view(batch_size, -1, self.num_heads, self.head_dim).transpose(1, 2)        K = K.view(batch_size, -1, self.num_heads, self.head_dim).transpose(1, 2)        V = V.view(batch_size, -1, self.num_heads, self.head_dim).transpose(1, 2)        scores = torch.matmul(Q, K.transpose(-2, -1)) / (self.head_dim ** 0.5)        attn_weights = F.softmax(scores, dim=-1)        attn_weights = self.dropout(attn_weights)        attn_output = torch.matmul(attn_weights, V)        attn_output = attn_output.transpose(1, 2).contiguous().view(            batch_size, -1, channels)        attn_output = self.out_proj(attn_output)        attn_output = self.dropout(attn_output)        attn_output = residual + attn_output        output = self.norm2(attn_output)        output = output + self.ffn(output)        output = output.permute(0, 2, 1)        return outputclass SemanticAwareConformerNoRefinement(nn.Module):    """    去除语义精炼层的语义感知Conformer模型    """    def __init__(self, n_mels=80, num_blocks=6, output_size=256, embedding_dim=192,                 input_layer="conv2d2", pos_enc_layer_type="rel_pos"):        super(SemanticAwareConformerNoRefinement, self).__init__()        self.num_blocks = num_blocks        # Conformer编码器        self.conformer = ConformerEncoder(            input_size=n_mels,            num_blocks=num_blocks,            output_size=output_size,            input_layer=input_layer,            pos_enc_layer_type=pos_enc_layer_type        )        # 池化层和全连接层        self.pooling = AttentiveStatisticsPooling(output_size * num_blocks)        self.bn = BatchNorm1d(input_size=output_size * num_blocks * 2)        self.fc = nn.Linear(output_size * num_blocks * 2, embedding_dim)        # 交叉注意力融合        self.cross_attn_fuser1 = CrossAttentionFusion(output_size)        self.cross_attn_fuser2 = CrossAttentionFusion(output_size)        self.cross_attn_fuser3 = CrossAttentionFusion(output_size)        # 增强语义特征金字塔（无精炼层版本）        self.semantic_fpn = EnhancedSemanticFeaturePyramidNoRefinement(output_size, output_size)        # 语义特征池化层        self.semantic_pooling = AttentiveStatisticsPooling(output_size)        self.semantic_bn = BatchNorm1d(input_size=output_size * 2)        self.semantic_fc = nn.Linear(output_size * 2, embedding_dim // 2)        # 分别归一化的最终融合权重        self.original_weight = nn.Parameter(torch.ones(1))  # 原始方法权重        self.semantic_weight = nn.Parameter(torch.ones(1))  # 语义方法权重        # 最终融合层        self.final_fc = nn.Linear(embedding_dim + embedding_dim // 2, embedding_dim)        self.output_size = output_size    def forward(self, feat):        # 预处理        feat = feat.squeeze(1).permute(0, 2, 1)        lens = torch.ones(feat.shape[0]).to(feat.device)        lens = torch.round(lens * feat.shape[1]).int()        masks = ~make_pad_mask(lens).unsqueeze(1)        if self.conformer.global_cmvn is not None:            feat = self.conformer.global_cmvn(feat)        xs, pos_emb, masks = self.conformer.embed(feat, masks)        mask_pad = masks        # 处理每一层        conformer_outputs = []        x = xs        for i in range(self.num_blocks):            x, masks, _ = self.conformer.encoders[i](x, masks, pos_emb, mask_pad)            conformer_outputs.append(x.permute(0, 2, 1))  # [B, C, T]        # 获取各层输出 [B, C, T] - 注意：现在所有层都有相同的时间步！        x0_0 = conformer_outputs[0]  # 低层语义        x0_1 = conformer_outputs[1]  # 低层语义        x0_2 = conformer_outputs[2]  # 中层语义        x0_3 = conformer_outputs[3]  # 中层语义        x0_4 = conformer_outputs[4]  # 高层语义        x0_5 = conformer_outputs[5]  # 高层语义        # 原版方法：拼接所有块的特征        original_feat = torch.cat(conformer_outputs, dim=1)        original_pooled = self.pooling(original_feat)        original_pooled = self.bn(original_pooled)        original_pooled = original_pooled.permute(0, 2, 1)        original_embedding = self.fc(original_pooled)        original_embedding = original_embedding.squeeze(1)        # 语义层次融合        # 使用交叉注意力进行层内语义融合        fused_low = self.cross_attn_fuser1(x0_0, x0_1)  # 融合低层语义        fused_mid = self.cross_attn_fuser2(x0_2, x0_3)  # 融合中层语义        fused_high = self.cross_attn_fuser3(x0_4, x0_5)  # 融合高层语义        # 使用增强语义特征金字塔进行跨语义层次融合（无精炼层）        semantic_feat = self.semantic_fpn(fused_low, fused_mid, fused_high)        # 语义特征池化        semantic_pooled = self.semantic_pooling(semantic_feat)        semantic_pooled = self.semantic_bn(semantic_pooled)        semantic_pooled = semantic_pooled.permute(0, 2, 1)        semantic_embedding = self.semantic_fc(semantic_pooled)        semantic_embedding = semantic_embedding.squeeze(1)        # 分别归一化的融合权重        fusion_weights = F.softmax(torch.stack([self.original_weight, self.semantic_weight]), dim=0)        w_original, w_semantic = fusion_weights        # 加权融合两种方法的输出        weighted_original = w_original * original_embedding        weighted_semantic = w_semantic * semantic_embedding        combined = torch.cat([weighted_original, weighted_semantic], dim=1)        final_embedding = self.final_fc(combined)        return final_embedding    def get_fusion_info(self):        """获取融合信息"""        # 获取语义融合信息        semantic_info = self.semantic_fpn.get_fusion_info()        # 获取最终融合权重        fusion_weights = F.softmax(torch.stack([self.original_weight, self.semantic_weight]), dim=0)        w_original, w_semantic = fusion_weights.detach().cpu().numpy()        final_fusion_info = f"\n最终融合权重: 原始方法[{w_original:.3f}] 语义方法[{w_semantic:.3f}]"        return semantic_info + final_fusion_infodef conformer_cat(n_mels=80, num_blocks=6, output_size=256, embedding_dim=192,                                input_layer="conv2d2", pos_enc_layer_type="rel_pos"):    """    创建去除语义精炼层的语义感知Conformer模型    """    model = SemanticAwareConformerNoRefinement(        n_mels=n_mels,        num_blocks=num_blocks,        output_size=output_size,        embedding_dim=embedding_dim,        input_layer=input_layer,        pos_enc_layer_type=pos_enc_layer_type    )    return model# 测试函数def test_semantic_model_no_refinement():    """测试去除语义精炼层的语义感知模型"""    print("测试去除语义精炼层的语义感知Conformer模型:")    print("=" * 60)    # 创建模型    model = conformer_cat(num_blocks=6)    # 测试输入    x = torch.randn(2, 1, 80, 300)  # [B, 1, F, T]    print(f"输入形状: {x.shape}")    # 前向传播    output = model(x)    print(f"输出形状: {output.shape}")    # 打印融合信息    print(f"\n融合策略:")    print(model.get_fusion_info())    # 参数统计    total_params = sum(p.numel() for p in model.parameters())    trainable_params = sum(p.numel() for p in model.parameters() if p.requires_grad)        # 计算参数减少量    # 创建原版模型进行比较    from conformer_cat import conformer_cat as create_original_model    original_model = create_original_model(num_blocks=6)    original_total_params = sum(p.numel() for p in original_model.parameters())        params_reduction = (original_total_params - total_params) / original_total_params * 100        print(f"\n参数统计:")    print(f"原版模型总参数: {original_total_params:,}")    print(f"消融模型总参数: {total_params:,}")    print(f"可训练参数: {trainable_params:,}")    print(f"参数减少: {params_reduction:.2f}%")    return modelif __name__ == "__main__":    model = test_semantic_model_no_refinement()